import pytest
from app.prompts.reflection import build_reflection_prompt
from app.prompts.synthesis import build_synthesis_prompt

class TestReflectionPrompts:
    def test_no_history_student(self):
        """First-session student gets non-history-referencing prompts."""
        context = {
            "compressedSummary": None,
            "sessionCount": 0,
            "topInterests": [],
        }
        activities = [
            {"name": "Math Club", "category": "ACADEMIC", "excitement": 4}
        ]
        system, user = build_reflection_prompt(context, activities, pulse_score=7)

        # Both prompts should be present and non-empty
        assert "student" in system.lower()
        assert "Math Club" in user

    def test_history_referenced_in_prompt(self):
        """Returning student sees history referenced in prompt."""
        context = {
            "compressedSummary": "Student shows strong pattern in environmental sciences...",
            "sessionCount": 4,
            "topInterests": ["environmental science", "data analysis"],
        }
        activities = [
            {"name": "Climate Club", "category": "EXTRACURRICULAR", "excitement": 5}
        ]
        _, user = build_reflection_prompt(context, activities, pulse_score=8)
        assert "environmental sciences" in user or "compressed history" in user.lower()

    def test_output_format_valid_json_instruction(self):
        """System prompt requires JSON output."""
        system, _ = build_reflection_prompt({}, [], None)
        assert "JSON" in system
        assert "promptText" in system
        assert "promptType" in system


class TestSynthesisPrompts:
    def test_compressed_summary_requirement(self):
        """System prompt enforces compressed summary word limit."""
        history = {
            "grade": 11,
            "sessionCount": 3,
            "createdAt": "2024-09-01",
            "sessions": [],
            "activities": [],
        }
        system, _ = build_synthesis_prompt(history)
        assert "400 words" in system or "compressed" in system.lower()
