describe('Sessions API', () => {
  describe('POST /api/sessions', () => {
    it('creates new session for current month', async () => {
      const mockStudent = createMockStudent()
      const mockSession = createMockSession(mockStudent.id)

      const { prisma } = await import('@compass/db')
      vi.mocked(prisma.student.findUnique).mockResolvedValue(mockStudent)
      vi.mocked(prisma.reflectionSession.findUnique).mockResolvedValue(null)
      vi.mocked(prisma.reflectionSession.create).mockResolvedValue(mockSession)

      const { POST } = await import('@/app/api/sessions/route')
      const req = new Request('http://localhost/api/sessions', { method: 'POST' })
      const res = await POST(req)
      const body = await res.json()

      expect(res.status).toBe(201)
      expect(body.success).toBe(true)
      expect(body.data.studentId).toBe(mockStudent.id)
    })

    it('returns existing session if already created this month', async () => {
      const mockStudent = createMockStudent()
      const existingSession = createMockSession(mockStudent.id)

      const { prisma } = await import('@compass/db')
      vi.mocked(prisma.student.findUnique).mockResolvedValue(mockStudent)
      vi.mocked(prisma.reflectionSession.findUnique).mockResolvedValue(existingSession)

      const { POST } = await import('@/app/api/sessions/route')
      const req = new Request('http://localhost/api/sessions', { method: 'POST' })
      const res = await POST(req)

      expect(res.status).toBe(200) // Not 201
      expect(prisma.reflectionSession.create).not.toHaveBeenCalled()
    })
  })
})
