### 13.1 Signal Summary Component

**File: `apps/web/components/student/SignalSummary.tsx`**

This is the primary "mirror" the student sees — their own patterns reflected back.

```typescript
'use client'

import { motion } from 'framer-motion'
import { staggerContainer, fadeUpVariant } from '@compass/ui'
import type { SignalProfile } from '@compass/types'

const SIGNAL_COLORS = {
  rising: { bg: 'bg-signal-strong/10', text: 'text-signal-strong', dot: 'bg-signal-strong' },
  stable: { bg: 'bg-signal-moderate/10', text: 'text-signal-moderate', dot: 'bg-signal-moderate' },
  fading: { bg: 'bg-slate-100', text: 'text-slate-400', dot: 'bg-slate-400' },
  emerging: { bg: 'bg-signal-emerging/10', text: 'text-signal-emerging', dot: 'bg-signal-emerging' },
}

interface SignalSummaryProps {
  profile: SignalProfile
}

export function SignalSummary({ profile }: SignalSummaryProps) {
  const clusters = (profile.interestClusters as any[])
    .sort((a, b) => b.intensity - a.intensity)
    .slice(0, 5)

  return (
    <div>
      <div className="flex items-center justify-between mb-5">
        <h3 className="font-display font-semibold text-slate-900">Your Signals</h3>
        <div className="flex items-center gap-2">
          <span className="text-xs text-slate-500">Breadth</span>
          <BreadthBar score={profile.breadthScore} />
          <span className="text-xs font-medium text-slate-700">
            {Math.round(profile.breadthScore)}/100
          </span>
        </div>
      </div>

      <motion.div
        variants={staggerContainer}
        initial="hidden"
        animate="visible"
        className="flex flex-wrap gap-2"
      >
        {clusters.map((cluster, i) => {
          const trend = cluster.trend as keyof typeof SIGNAL_COLORS
          const colors = SIGNAL_COLORS[trend] || SIGNAL_COLORS.stable
          return (
            <motion.span
              key={cluster.label}
              variants={fadeUpVariant}
              custom={i}
              className={`signal-badge ${colors.bg} ${colors.text}`}
            >
              <span className={`w-1.5 h-1.5 rounded-full ${colors.dot}`} />
              {cluster.label}
              <span className="opacity-60 text-xs">{cluster.intensity.toFixed(0)}</span>
            </motion.span>
          )
        })}
      </motion.div>

      {(profile.trajectoryShifts as any[]).length > 0 && (
        <div className="mt-4 pt-4 border-t border-white/40">
          <p className="text-xs text-slate-500 mb-2">Recent shift detected</p>
          {((profile.trajectoryShifts as any[]).slice(0, 1)).map((shift: any, i: number) => (
            <div key={i} className="flex items-center gap-2 text-sm">
              <span className="text-slate-600">{shift.fromInterest}</span>
              <span className="text-slate-400">→</span>
              <span className="font-medium text-signal-emerging">{shift.toInterest}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

function BreadthBar({ score }: { score: number }) {
  return (
    <div className="w-20 h-1.5 bg-slate-200 rounded-full overflow-hidden">
      <motion.div
        className="h-full bg-accent-primary rounded-full"
        initial={{ width: 0 }}
        animate={{ width: `${score}%` }}
        transition={{ duration: 0.8, ease: 'easeOut', delay: 0.2 }}
      />
    </div>
  )
}
```

### 13.2 Privacy Review Component (Step 5)

**File: `apps/web/components/student/PrivacyReview.tsx`**

This is the critical trust component — students control exactly what counselors see.

```typescript
'use client'

import { useState } from 'react'
import { motion } from 'framer-motion'
import { staggerContainer, fadeUpVariant } from '@compass/ui'

interface PrivacyOption {
  key: string
  label: string
  description: string
  defaultOn: boolean
}

const PRIVACY_OPTIONS: PrivacyOption[] = [
  {
    key: 'shareInterestClusters',
    label: 'Interest clusters',
    description: 'The themes and patterns in your activities (e.g., "creative-technical")',
    defaultOn: true,
  },
  {
    key: 'shareBreadthScore',
    label: 'Exploration breadth score',
    description: 'A number (0-100) showing how widely you\'ve explored different areas',
    defaultOn: true,
  },
  {
    key: 'shareTrajectoryShifts',
    label: 'Trajectory changes',
    description: 'Patterns of how your interests have shifted over time',
    defaultOn: true,
  },
  {
    key: 'shareCharacterSignals',
    label: 'Character signals',
    description: 'Values and traits that show up across your activities',
    defaultOn: true,
  },
]

export function PrivacyReview({ sessionId, reflections, onComplete }: PrivacyReviewProps) {
  const [settings, setSettings] = useState<Record<string, boolean>>(
    Object.fromEntries(PRIVACY_OPTIONS.map(o => [o.key, o.defaultOn]))
  )
  const [reflectionSharing, setReflectionSharing] = useState<Record<string, boolean>>(
    Object.fromEntries((reflections ?? []).map((r: any) => [r.id, false]))
  )
  const [isSaving, setIsSaving] = useState(false)

  const handleSubmit = async () => {
    setIsSaving(true)
    // Save privacy settings
    await fetch('/api/privacy', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(settings),
    })

    // Update per-reflection sharing
    await Promise.all(
      Object.entries(reflectionSharing).map(([id, shared]) =>
        fetch(`/api/reflections/${id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ isSharedWithCounselor: shared }),
        })
      )
    )

    setIsSaving(false)
    onComplete({ privacySettings: settings, reflectionSharing })
  }

  return (
    <motion.div variants={staggerContainer} initial="hidden" animate="visible">
      <motion.div variants={fadeUpVariant} custom={0}>
        <h2 className="text-2xl font-display font-bold text-slate-900 mb-2">
          Your reflection is yours.
        </h2>
        <p className="text-slate-500 mb-8">
          Choose what your counselor can see. You can change this any time.
        </p>
      </motion.div>

      <motion.div variants={fadeUpVariant} custom={1} className="glass-panel p-5 mb-6">
        <h3 className="font-semibold text-sm text-slate-700 mb-4">Signal data</h3>
        <div className="space-y-4">
          {PRIVACY_OPTIONS.map((option, i) => (
            <label key={option.key} className="flex items-start gap-3 cursor-pointer">
              <div className="relative mt-0.5">
                <input
                  type="checkbox"
                  checked={settings[option.key]}
                  onChange={e => setSettings(prev => ({
                    ...prev,
                    [option.key]: e.target.checked,
                  }))}
                  className="sr-only"
                />
                <div className={`w-5 h-5 rounded border-2 flex items-center justify-center
                  transition-colors duration-150
                  ${settings[option.key]
                    ? 'bg-accent-primary border-accent-primary'
                    : 'bg-white border-slate-300'
                  }`}
                >
                  {settings[option.key] && (
                    <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                    </svg>
                  )}
                </div>
              </div>
              <div>
                <p className="text-sm font-medium text-slate-800">{option.label}</p>
                <p className="text-xs text-slate-500">{option.description}</p>
              </div>
            </label>
          ))}
        </div>
      </motion.div>

      {reflections && reflections.length > 0 && (
        <motion.div variants={fadeUpVariant} custom={2} className="glass-panel p-5 mb-6">
          <h3 className="font-semibold text-sm text-slate-700 mb-1">Your written responses</h3>
          <p className="text-xs text-slate-500 mb-4">
            These are private by default. Share specific ones if you want.
          </p>
          <div className="space-y-3">
            {reflections.map((reflection: any) => (
              <label key={reflection.id} className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={reflectionSharing[reflection.id] ?? false}
                  onChange={e => setReflectionSharing(prev => ({
                    ...prev,
                    [reflection.id]: e.target.checked,
                  }))}
                  className="mt-1"
                />
                <div>
                  <p className="text-xs text-slate-600 line-clamp-2">{reflection.promptText}</p>
                  {reflection.responseText && (
                    <p className="text-xs text-slate-400 mt-0.5 line-clamp-1 italic">
                      "{reflection.responseText}"
                    </p>
                  )}
                </div>
              </label>
            ))}
          </div>
        </motion.div>
      )}

      <motion.div variants={fadeUpVariant} custom={3}>
        <button
          onClick={handleSubmit}
          disabled={isSaving}
          className="btn-primary w-full"
        >
          {isSaving ? 'Saving...' : 'Submit Reflection'}
        </button>
        <p className="text-xs text-slate-400 text-center mt-3">
          Raw reflection text is never shared unless you explicitly choose it above.
        </p>
      </motion.div>
    </motion.div>
  )
}
```

